#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code)
# =============================================================================
"""
Step ID: step07
Step Name: model_diagnostics_assumptions
RQ: results/ch7/7.7.2
Generated: 2026-01-09

PURPOSE:
Comprehensive assumption checking, outlier analysis, and model adequacy assessment
for ANOVA results. Test normality, homoscedasticity, and identify outliers.

EXPECTED INPUTS:
  - results/ch7/7.7.2/data/step05_anova_results.csv
  - results/ch7/7.7.2/data/step04_demographic_data.csv

EXPECTED OUTPUTS:
  - results/ch7/7.7.2/data/step07_assumption_checks.csv
  - results/ch7/7.7.2/data/step07_outlier_analysis.csv
  - results/ch7/7.7.2/data/step07_power_analysis.csv
  - results/ch7/7.7.2/data/step07_robustness_tests.csv
  - results/ch7/7.7.2/data/step07_remedial_actions.txt

g_code REASONING:
- Comprehensive assumption testing for all ANOVA models
- Outlier identification using IQR method
- Non-parametric robustness checks (Kruskal-Wallis)
- Power analysis for sample adequacy
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy import stats as scipy_stats
from statsmodels.stats.power import FTestAnovaPower
import traceback

PROJECT_ROOT = Path(__file__).resolve().parents[4]
sys.path.insert(0, str(PROJECT_ROOT))

from tools.validation import validate_model_convergence

RQ_DIR = Path(__file__).resolve().parents[1]
LOG_FILE = RQ_DIR / "logs" / "step07_model_diagnostics_assumptions.log"

def log(msg):
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

if __name__ == "__main__":
    try:
        log("[START] Step 07: Model Diagnostics and Assumptions")

        # Load data
        log("[LOAD] Loading ANOVA results and demographic data...")
        anova_df = pd.read_csv(RQ_DIR / "data" / "step05_anova_results.csv")
        demo_df = pd.read_csv(RQ_DIR / "data" / "step04_demographic_data.csv")

        log(f"[LOADED] {len(anova_df)} ANOVA results, {len(demo_df)} participants")

        demo_vars = anova_df['variable'].unique()

        # Identify available grouping schemes
        grouping_schemes = {}
        if 'Group_RAVLT_Total' in demo_df.columns:
            grouping_schemes['RAVLT_Total'] = 'Group_RAVLT_Total'
        elif 'Group' in demo_df.columns:
            grouping_schemes['RAVLT_Total'] = 'Group'
        if 'Group_RAVLT_Pct_Ret' in demo_df.columns:
            grouping_schemes['RAVLT_Pct_Ret'] = 'Group_RAVLT_Pct_Ret'

        # Assumption checks
        log("[CHECK] Testing ANOVA assumptions...")

        assumption_results = []

        for scheme_label, group_col in grouping_schemes.items():
            log(f"\n[CHECK] === {scheme_label} ===")

            for var in demo_vars:
                df_complete = demo_df[[group_col, var]].dropna()
                df_complete = df_complete.rename(columns={group_col: 'Group'})

                # Test normality per group (Shapiro-Wilk)
                for group_name in df_complete['Group'].unique():
                    group_data = df_complete[df_complete['Group'] == group_name][var].values

                    if len(group_data) >= 3:
                        shapiro_stat, shapiro_p = scipy_stats.shapiro(group_data)
                        skewness = scipy_stats.skew(group_data)
                        kurtosis = scipy_stats.kurtosis(group_data)

                        assumption_results.append({
                            'metric': scheme_label,
                            'variable': var,
                            'group': group_name,
                            'n': len(group_data),
                            'shapiro_W': shapiro_stat,
                            'shapiro_p': shapiro_p,
                            'skewness': skewness,
                            'kurtosis': kurtosis,
                            'normality_assumption': 'met' if shapiro_p >= 0.05 else 'violated'
                        })

                        log(f"[NORM] {scheme_label}/{var} - {group_name}: Shapiro W={shapiro_stat:.4f}, p={shapiro_p:.4f}")

                # Test homogeneity of variance (Levene's test)
                groups = [df_complete[df_complete['Group'] == g][var].values for g in df_complete['Group'].unique()]
                levene_stat, levene_p = scipy_stats.levene(*groups)

                log(f"[HOMOGEN] {scheme_label}/{var}: Levene F={levene_stat:.4f}, p={levene_p:.4f}")

                # Update assumption results with Levene test (for current scheme+var)
                for i, res in enumerate(assumption_results):
                    if res.get('metric') == scheme_label and res['variable'] == var and 'levene_F' not in res:
                        assumption_results[i]['levene_F'] = levene_stat
                        assumption_results[i]['levene_p'] = levene_p
                        assumption_results[i]['homoscedasticity_assumption'] = 'met' if levene_p >= 0.05 else 'violated'

        assumption_df = pd.DataFrame(assumption_results)

        # Outlier analysis (same for both schemes since it's about raw values, not groups)
        log("[OUTLIER] Identifying outliers using IQR method...")

        outlier_results = []

        # Use first available group column for outlier reporting
        primary_group_col = list(grouping_schemes.values())[0] if grouping_schemes else 'Group'

        for var in demo_vars:
            cols_for_outlier = ['UID', primary_group_col, var]
            cols_for_outlier = [c for c in cols_for_outlier if c in demo_df.columns]
            df_complete = demo_df[cols_for_outlier].dropna()
            if primary_group_col in df_complete.columns:
                df_complete = df_complete.rename(columns={primary_group_col: 'Group'})

            q1 = df_complete[var].quantile(0.25)
            q3 = df_complete[var].quantile(0.75)
            iqr = q3 - q1
            lower_bound = q1 - 1.5 * iqr
            upper_bound = q3 + 1.5 * iqr

            outliers = df_complete[(df_complete[var] < lower_bound) | (df_complete[var] > upper_bound)]

            log(f"[OUTLIER] {var}: {len(outliers)} outliers detected (IQR method)")

            for _, row in outliers.iterrows():
                outlier_results.append({
                    'variable': var,
                    'UID': row['UID'],
                    'Group': row.get('Group', 'N/A'),
                    'value': row[var],
                    'lower_bound': lower_bound,
                    'upper_bound': upper_bound,
                    'outlier_type': 'low' if row[var] < lower_bound else 'high'
                })

        outlier_df = pd.DataFrame(outlier_results)

        # Power analysis
        log("[POWER] Computing power analysis for sample adequacy...")

        power_results = []
        power_test = FTestAnovaPower()

        for _, row in anova_df.iterrows():
            if not pd.isna(row['F_stat']) and not pd.isna(row['eta_squared']):
                f2 = row['eta_squared'] / (1 - row['eta_squared']) if row['eta_squared'] < 1 else np.nan
                n = row['df1'] + row['df2'] + 1

                if not pd.isna(f2) and f2 > 0:
                    power = power_test.solve_power(
                        effect_size=f2,
                        nobs=n,
                        alpha=0.05
                    )

                    power_results.append({
                        'metric': row.get('metric', 'RAVLT_Total'),
                        'variable': row['variable'],
                        'effect_size_f2': f2,
                        'sample_size': n,
                        'observed_power': power,
                        'adequate': 'yes' if power >= 0.80 else 'no'
                    })

                    log(f"[POWER] {row.get('metric', 'RAVLT_Total')}/{row['variable']}: n={n}, f2={f2:.4f}, power={power:.4f}")

        power_df = pd.DataFrame(power_results)

        # Non-parametric robustness tests (Kruskal-Wallis)
        log("[ROBUST] Running Kruskal-Wallis tests (non-parametric alternative)...")

        robustness_results = []

        for scheme_label, group_col in grouping_schemes.items():
            for var in demo_vars:
                df_complete = demo_df[[group_col, var]].dropna()
                df_complete = df_complete.rename(columns={group_col: 'Group'})
                groups = [df_complete[df_complete['Group'] == g][var].values for g in df_complete['Group'].unique()]

                kw_stat, kw_p = scipy_stats.kruskal(*groups)

                robustness_results.append({
                    'metric': scheme_label,
                    'variable': var,
                    'kruskal_wallis_H': kw_stat,
                    'kruskal_wallis_p': kw_p,
                    'conclusion': 'robust' if kw_p < 0.05 else 'not_robust'
                })

                log(f"[KRUSKAL] {scheme_label}/{var}: H={kw_stat:.4f}, p={kw_p:.4f}")

        robustness_df = pd.DataFrame(robustness_results)

        # Remedial actions summary
        remedial_text = f"""REMEDIAL ACTIONS SUMMARY - RQ 7.7.2

Generated: {pd.Timestamp.now().isoformat()}

Assumption Violations:
"""

        normality_violations = assumption_df[assumption_df['normality_assumption'] == 'violated']
        homogen_violations = assumption_df[assumption_df['homoscedasticity_assumption'] == 'violated']

        if len(normality_violations) > 0:
            remedial_text += f"\nNormality violations: {len(normality_violations)} group-variable combinations\n"
            for var in normality_violations['variable'].unique():
                remedial_text += f"  - {var}\n"
        else:
            remedial_text += "\nNormality: All groups meet assumption\n"

        if len(homogen_violations) > 0:
            remedial_text += f"\nHomoscedasticity violations: {len(homogen_violations['variable'].unique())} variables\n"
            for var in homogen_violations['variable'].unique():
                remedial_text += f"  - {var}\n"
        else:
            remedial_text += "\nHomoscedasticity: All variables meet assumption\n"

        remedial_text += f"\nOutliers identified: {len(outlier_df)}\n"
        remedial_text += f"\nNon-parametric robustness checks:\n"
        for _, row in robustness_df.iterrows():
            remedial_text += f"  - {row['variable']}: Kruskal-Wallis p={row['kruskal_wallis_p']:.4f} ({row['conclusion']})\n"

        # Save outputs
        log("[SAVE] Saving diagnostic results...")

        output_assumptions = RQ_DIR / "data" / "step07_assumption_checks.csv"
        assumption_df.to_csv(output_assumptions, index=False, encoding='utf-8')
        log(f"[SAVED] {output_assumptions.name} ({len(assumption_df)} rows)")

        output_outliers = RQ_DIR / "data" / "step07_outlier_analysis.csv"
        if len(outlier_df) > 0:
            outlier_df.to_csv(output_outliers, index=False, encoding='utf-8')
            log(f"[SAVED] {output_outliers.name} ({len(outlier_df)} rows)")
        else:
            pd.DataFrame().to_csv(output_outliers, index=False, encoding='utf-8')
            log(f"[SAVED] {output_outliers.name} (no outliers detected)")

        output_power = RQ_DIR / "data" / "step07_power_analysis.csv"
        power_df.to_csv(output_power, index=False, encoding='utf-8')
        log(f"[SAVED] {output_power.name} ({len(power_df)} rows)")

        output_robustness = RQ_DIR / "data" / "step07_robustness_tests.csv"
        robustness_df.to_csv(output_robustness, index=False, encoding='utf-8')
        log(f"[SAVED] {output_robustness.name} ({len(robustness_df)} rows)")

        output_remedial = RQ_DIR / "data" / "step07_remedial_actions.txt"
        with open(output_remedial, 'w', encoding='utf-8') as f:
            f.write(remedial_text)
        log(f"[SAVED] {output_remedial.name}")

        log("[SUCCESS] Step 07 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
